<script setup lang="ts">import{onMounted,ref}from'vue';import{callApi}from'../api';const modules=[['开票申请','合同额度控制'],['销项发票','开票与红冲'],['收款登记','预收与正常收款'],['发票核销','一收多票、一票多收'],['费用报销','主表与明细汇总'],['项目付款','多次付款明细'],['日常采购','非项目费用与采购审批']];const summary=ref({invoicedAmount:'0.00',receivedAmount:'0.00',paidAmount:'0.00'}),error=ref<string|null>(null);onMounted(async()=>{try{summary.value=await callApi('finance.summary',{})}catch(e){error.value=e instanceof Error?e.message:'加载失败'}})</script>
<template><main class="page"><header class="page-header"><div><p class="eyebrow">CASH & BILLING</p><h1>收支管理</h1></div></header><p v-if="error" class="error">{{error}}</p><section class="contract-panels"><article><p>累计开票</p><strong>¥ {{summary.invoicedAmount}}</strong><small>有效销项发票</small></article><article><p>累计收款</p><strong>¥ {{summary.receivedAmount}}</strong><small>实际到账</small></article><article><p>累计支付</p><strong>¥ {{summary.paidAmount}}</strong><small>实际经营付款</small></article></section><section class="module-grid"><article v-for="([title,detail],i) in modules" :key="title" class="module-card"><span class="module-icon">{{i+1}}</span><h2>{{title}}</h2><p>{{detail}}</p></article></section></main></template>
